[
  {
    "section_id": "s01",
    "title": "Overview and Definitions of Intermittent Fasting and Metabolic Syndrome",
    "description": "Define intermittent fasting protocols (TRE, ADF, 5:2, FMD) and metabolic syndrome diagnostic criteria. Frame the research question and scope."
  },
  {
    "section_id": "s02",
    "title": "Pooled Effect Sizes on Metabolic Outcomes",
    "description": "Synthesize meta-analytic pooled point estimates (SMD/WMD with 95% CI) for fasting blood glucose, HbA1c, HOMA-IR, LDL-C, IL-6, body weight, BMI, and blood pressure in adults with metabolic syndrome."
  },
  {
    "section_id": "s03",
    "title": "Heterogeneity and Methodological Considerations",
    "description": "Characterize dominant moderators of heterogeneity (I² up to 93.8%) — protocol type, duration, sex, BMI — and assess publication bias via Egger test, funnel plots, and GRADE certainty."
  },
  {
    "section_id": "s04",
    "title": "Long-term Cardiovascular Safety and the AHA 2024 Signal",
    "description": "Present the AHA 2024 Zhong/Chen NHANES-based 91% cardiovascular mortality signal for <8h eating windows, the peer-reviewed publication (PMID 40849219), and the expert methodological critique."
  },
  {
    "section_id": "s05",
    "title": "Free-Living Observational Evidence — Ramadan and Epidemiology",
    "description": "Contrast the NHANES signal with the Ramadan systematic-review literature across Muslim populations showing null or mildly beneficial CV effects, plus other population-level epidemiology."
  },
  {
    "section_id": "s06",
    "title": "Mechanisms — Gut Microbiome, Circadian, and Autophagy Pathways",
    "description": "Summarize emerging mechanistic evidence on IF — SCFA production, microbiome modulation, circadian alignment, autophagy, and mTOR/AMPK signaling."
  },
  {
    "section_id": "s07",
    "title": "Real-World Evidence from Commercial IF Apps",
    "description": "Present industry-facing real-world evidence (JMIR 52-week LIFE app study, SIMPLE app) showing BMI-stratified benefits — strong in BMI ≥40, absent in lower BMI."
  },
  {
    "section_id": "s08",
    "title": "Safety, Adverse Events, and Disordered Eating Risk",
    "description": "Enumerate documented harms: hypoglycemia in diabetic patients, disordered eating risk especially in adolescents, micronutrient compromise, and interaction with food insecurity in LMIC settings."
  },
  {
    "section_id": "s09",
    "title": "Clinical Implications, Patient Selection, and Knowledge Gaps",
    "description": "Translate evidence into clinical guidance for patient selection, contraindications, and research priorities — long-duration RCTs, LMIC trials, head-to-head with GLP-1, and mechanistic depth."
  }
]
